4	// MARK: - Recording State
5	
6	enum RecordingState: Equatable {
7	    case idle
8	    case recording(startedAt: Date)
9	    case processing
10	
11	    var isRecording: Bool {
12	        if case .recording = self { return true }
13	        return false
14	    }
15	
16	    var duration: TimeInterval? {
17	        guard case .recording(let start) = self else { return nil }
18	        return Date().timeIntervalSince(start)
19	    }
20	}
21	
22	// MARK: - Transcription Entry
23	
24	struct TranscriptionEntry: Identifiable, Equatable {
25	    let id = UUID()
26	    let text: String
27	    let timestamp: Date
28	    let duration: TimeInterval // audio segment duration in seconds
29	
30	    var formattedTimestamp: String {
31	        let f = DateFormatter()
32	        f.timeStyle = .medium
33	        f.dateStyle = .none
34	        return f.string(from: timestamp)
35	    }
36	}
37	
38	// MARK: - App State (Task 2.3)
39	
40	@MainActor
41	final class AppState: ObservableObject {
42	    // Recording
43	    @Published var recordingState: RecordingState = .idle
44	    @Published var audioLevel: Float = 0.0          // 0.0 - 1.0 for waveform
45	    @Published var bufferWarning: Bool = false       // ring buffer overflow warning
46	
47	    // Transcription
48	    @Published var entries: [TranscriptionEntry] = []
49	    @Published var isModelLoaded: Bool = false
50	    @Published var modelLoadError: String? = nil
51	
52	    // Errors
53	    @Published var micPermissionDenied: Bool = false
54	    @Published var accessibilityPermissionGranted: Bool = false
55	
56	    // Preferences
57	    @Published var selectedModel: WhisperModel = .tiny
58	    @Published var vadSilenceThresholdMs: Int = 500
59	
60	    // E2E 测试钩子：由 AppDelegate 注入，供 SwiftUI 按钮调用
61	    var toggleRecordingAction: (() -> Void)?
62	
63	    // MARK: Computed
64	
65	    var allTranscriptionText: String {
66	        entries.map(\.text).joined(separator: "\n")
67	    }
68	
69	    var recordingDuration: TimeInterval {
70	        recordingState.duration ?? 0
71	    }
72	
73	    // MARK: Mutations
74	
75	    func appendEntry(_ entry: TranscriptionEntry) {
76	        entries.append(entry)
77	    }
78	
79	    func clearSession() {
80	        entries.removeAll()
81	    }
82	
83	    func startRecording() {
84	        recordingState = .recording(startedAt: Date())
85	    }
86	
87	    func stopRecording() {
88	        recordingState = .idle
89	        audioLevel = 0
90	    }
91	}
