4	// MARK: - Model Download State
5	
6	enum ModelLoadState {
7	    case idle
8	    case downloading(progress: Double)
9	    case loading
10	    case ready
11	    case failed(Error)
12	}
13	
14	// MARK: - Whisper Model Manager (Tasks 5.1 & 5.2)
15	
16	final class WhisperModelManager: NSObject {
17	
18	    let statePublisher = CurrentValueSubject<ModelLoadState, Never>(.idle)
19	
20	    private(set) var whisperContext: WhisperContext?
21	
22	    // ~/Library/Application Support/VoicePepper/models/
23	    static var modelsDirectory: URL {
24	        let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
25	        return appSupport.appendingPathComponent("VoicePepper/models", isDirectory: true)
26	    }
27	
28	    // MARK: - Load or Download
29	
30	    /// Check local model exists; if not, download it first, then load.
31	    func ensureModel(_ model: WhisperModel) async {
32	        let localPath = Self.modelsDirectory.appendingPathComponent(model.filename)
33	        NSLog("[WhisperModelManager] ensureModel: \(model.rawValue), path=\(localPath.path)")
34	
35	        if FileManager.default.fileExists(atPath: localPath.path) {
36	            let fileSize = (try? FileManager.default.attributesOfItem(atPath: localPath.path)[.size] as? Int) ?? 0
37	            NSLog("[WhisperModelManager] 本地模型存在，大小=\(fileSize) bytes，开始加载")
38	            await loadModel(at: localPath)
39	        } else {
40	            NSLog("[WhisperModelManager] 本地模型不存在，开始下载 url=\(model.downloadURL)")
41	            await downloadAndLoad(model: model, destination: localPath)
42	        }
43	    }
44	
45	    // MARK: - Private: Load
46	
47	    private func loadModel(at url: URL) async {
48	        NSLog("[WhisperModelManager] loadModel 开始: \(url.lastPathComponent)")
49	        statePublisher.send(.loading)
50	
51	        do {
52	            let t0 = Date()
53	            let context = try WhisperContext(modelPath: url.path)
54	            let elapsed = Date().timeIntervalSince(t0)
55	            self.whisperContext = context
56	            NSLog("[WhisperModelManager] 模型加载成功，耗时 %.2fs", elapsed)
57	            statePublisher.send(.ready)
58	        } catch {
59	            NSLog("[WhisperModelManager] 模型加载失败: \(error)")
60	            statePublisher.send(.failed(error))
61	        }
62	    }
63	
64	    // MARK: - Private: Download (Task 5.2)
65	
66	    private func downloadAndLoad(model: WhisperModel, destination: URL) async {
67	        // Create directory if needed
68	        try? FileManager.default.createDirectory(
69	            at: Self.modelsDirectory,
70	            withIntermediateDirectories: true
71	        )
72	
73	        statePublisher.send(.downloading(progress: 0))
74	
75	        do {
76	            let (localTempURL, response) = try await URLSession.shared.download(from: model.downloadURL) { bytesWritten, totalBytesWritten, totalExpected in
77	                let progress = totalExpected > 0 ? Double(totalBytesWritten) / Double(totalExpected) : 0
78	                DispatchQueue.main.async { [weak self] in
79	                    self?.statePublisher.send(.downloading(progress: progress))
80	                }
81	            }
82	
83	            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
84	                throw URLError(.badServerResponse)
85	            }
86	
87	            try FileManager.default.moveItem(at: localTempURL, to: destination)
88	            await loadModel(at: destination)
89	
90	        } catch {
91	            statePublisher.send(.failed(error))
92	        }
93	    }
94	}
95	
96	// MARK: - URLSession download with progress
97	
98	extension URLSession {
99	    func download(from url: URL, progress: @escaping (Int64, Int64, Int64) -> Void) async throws -> (URL, URLResponse) {
100	        return try await withCheckedThrowingContinuation { continuation in
101	            let task = self.downloadTask(with: url) { tempURL, response, error in
102	                if let error {
103	                    continuation.resume(throwing: error)
104	                } else if let tempURL, let response {
105	                    continuation.resume(returning: (tempURL, response))
106	                } else {
107	                    continuation.resume(throwing: URLError(.unknown))
108	                }
109	            }
110	
111	            // Track progress via KVO observation
112	            let observation = task.observe(\.countOfBytesReceived, options: [.new]) { task, _ in
113	                progress(task.countOfBytesReceived, task.countOfBytesReceived, task.countOfBytesExpectedToReceive)
114	            }
115	
116	            task.resume()
117	
118	            // Hold observation alive until task completes
119	            withExtendedLifetime(observation) {}
120	        }
121	    }
122	}
