// MARK: - Transcription Popover View (Task 6.2)
// Main panel: status bar at top, transcript list, action buttons at bottom.

struct TranscriptionPopoverView: View {
    @EnvironmentObject var appState: AppState

    @State private var showClearConfirm = false
    @State private var showCopiedFeedback = false

    var body: some View {
        VStack(spacing: 0) {

            // Top: Recording status bar (timer + waveform) - Task 6.4
            RecordingStatusBar()
                .environmentObject(appState)
                .accessibilityElement(children: .contain)
                .accessibilityIdentifier("recordingStatusBar")

            Divider()

            // Middle: Transcript list (scrollable) - Task 6.3
            TranscriptionListView()
                .environmentObject(appState)
                .frame(minHeight: 300)

            Divider()

            // Bottom: Action bar
            actionBar
        }
        .frame(width: 400, height: 460)
        .background(Color(NSColor.windowBackgroundColor))
        // .contain 保留子元素各自的 accessibilityIdentifier，避免 SwiftUI 平铺时被父 id 覆盖
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("transcriptionPopover")
        // E2E 测试钩子：零尺寸隐藏按钮，通过 AX 触发录音切换
        .overlay(alignment: .topLeading) {
            Button("") {
                NSLog("[TestButton] testToggleRecordingButton pressed")
                appState.toggleRecordingAction?()
            }
            .frame(width: 1, height: 1)
            .opacity(0.01)
            .accessibilityLabel("Toggle Recording")
            .accessibilityIdentifier("testToggleRecordingButton")
        }
    }

    // MARK: Action Bar

    private var actionBar: some View {
        HStack {
            // 偏好设置入口
            Button {
                NSApp.sendAction(Selector(("showSettingsWindow:")), to: nil, from: nil)
                NSApp.activate(ignoringOtherApps: true)
            } label: {
                Image(systemName: "gearshape")
                    .font(.caption)
            }
            .buttonStyle(.borderless)
            .help("偏好设置 (模型选择、快捷键…)")
            .accessibilityIdentifier("settingsButton")

            // Clear session (Task 6.7)
            Button(role: .destructive) {
                showClearConfirm = true
            } label: {
                Label("清除", systemImage: "trash")
                    .font(.caption)
            }
            .buttonStyle(.borderless)
            .disabled(appState.entries.isEmpty)
            .accessibilityIdentifier("clearButton")
            .confirmationDialog(
                "清除所有转录内容？",
                isPresented: $showClearConfirm,
                titleVisibility: .visible
            ) {
                Button("清除", role: .destructive) {
                    appState.clearSession()
                }
                Button("取消", role: .cancel) {}
            }

            Spacer()

            // Entry count
            if !appState.entries.isEmpty {
                Text("\(appState.entries.count) 条")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }

            // Copy all (Task 6.6)
            Button {
                copyAll()
            } label: {
                Label(showCopiedFeedback ? "已复制" : "复制全部", systemImage: "doc.on.doc")
                    .font(.caption)
            }
            .buttonStyle(.bordered)
            .disabled(appState.entries.isEmpty)
            .accessibilityIdentifier("copyAllButton")
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 8)
    }

    // MARK: Copy Action (Task 6.6)

    private func copyAll() {
        NSPasteboard.general.clearContents()
        NSPasteboard.general.setString(appState.allTranscriptionText, forType: .string)

        // 200ms feedback
        withAnimation {
            showCopiedFeedback = true
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            withAnimation {
                showCopiedFeedback = false
            }
        }
    }
}

import AppKit
import SwiftUI
import Combine

// MARK: - Status Bar Manager (Task 2.2)

@MainActor
final class StatusBarManager {

    private var statusItem: NSStatusItem
    private var popover: NSPopover
    private var appState: AppState
    private var cancellables = Set<AnyCancellable>()

    // Pulse animation timer for recording state
    private var pulseTimer: Timer?
    private var pulsePhase: Bool = false

    init(appState: AppState) {
        self.appState = appState
        self.statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.squareLength)
        self.popover = NSPopover()

        configurePopover()
        configureStatusItem()
        observeState()
    }

    // MARK: Configuration

    private func configurePopover() {
        let popoverView = TranscriptionPopoverView()
            .environmentObject(appState)

        let contentVC = NSHostingController(rootView: popoverView)
        contentVC.view.frame = NSRect(x: 0, y: 0, width: 400, height: 500)

        popover.contentViewController = contentVC
        popover.behavior = .transient
        popover.animates = true
    }

    private func configureStatusItem() {
        guard let button = statusItem.button else { return }
        button.image = NSImage(systemSymbolName: "mic", accessibilityDescription: "VoicePepper")
        button.imagePosition = .imageOnly
        button.action = #selector(handleClick)
        button.sendAction(on: [.leftMouseUp, .rightMouseUp])
        button.target = self
        button.setAccessibilityIdentifier("statusBarMicButton")

        updateIcon(isRecording: false)
    }

    // MARK: Click Handling

    @objc private func handleClick() {
        guard let event = NSApp.currentEvent else { return }
        if event.type == .rightMouseUp {
            showContextMenu()
        } else {
            togglePopover()
        }
    }

    private func showContextMenu() {
        let menu = NSMenu()
        menu.addItem(withTitle: "偏好设置…", action: #selector(openPreferences), keyEquivalent: ",")
        menu.addItem(.separator())
        menu.addItem(withTitle: "退出 VoicePepper", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q")
        for item in menu.items { item.target = self }
        statusItem.menu = menu
        statusItem.button?.performClick(nil)
        // 用后清除，保持左键单击正常
        DispatchQueue.main.async { [weak self] in self?.statusItem.menu = nil }
    }

    @objc private func openPreferences() {
        NSApp.sendAction(Selector(("showSettingsWindow:")), to: nil, from: nil)
        NSApp.activate(ignoringOtherApps: true)
    }

    private func observeState() {
        appState.$recordingState
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                self?.updateIcon(isRecording: state.isRecording)
            }
            .store(in: &cancellables)
    }

    // MARK: Icon Update (Task 6.1 - pulse animation)

    private func updateIcon(isRecording: Bool) {
        guard let button = statusItem.button else { return }

        if isRecording {
            // Start pulse animation
            pulseTimer?.invalidate()
            pulseTimer = Timer.scheduledTimer(withTimeInterval: 0.6, repeats: true) { [weak self, weak button] _ in
                Task { @MainActor [weak self, weak button] in
                    guard let self, let button else { return }
                    self.pulsePhase.toggle()
                    let symbolName = self.pulsePhase ? "mic.fill" : "mic"
                    button.image = NSImage(systemSymbolName: symbolName, accessibilityDescription: "Recording")
                    button.contentTintColor = .systemRed
                }
            }
        } else {
            pulseTimer?.invalidate()
            pulseTimer = nil
            pulsePhase = false
            button.image = NSImage(systemSymbolName: "mic", accessibilityDescription: "VoicePepper")
            button.contentTintColor = nil
        }
    }

    // MARK: Popover Toggle

    // MARK: Popover Toggle

    @objc private func togglePopover() {
        if popover.isShown {
            popover.performClose(nil)
        } else {
            guard let button = statusItem.button else { return }
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
            popover.contentViewController?.view.window?.makeKey()
        }
    }
}

import Foundation
import Combine

// MARK: - Transcription Service
// Receives AudioSegments, queues them for serial whisper.cpp transcription,
// and publishes results back to AppState.
// Subscribes to appState.$selectedModel for runtime hot-switching.

final class TranscriptionService {

    // Published: model ready / error (wired in AppDelegate)
    let modelReadyPublisher = PassthroughSubject<Bool, Never>()
    let modelErrorPublisher = PassthroughSubject<String, Never>()

    private let appState: AppState
    let modelManager: WhisperModelManager

    // Serial queue: prevents concurrent whisper inference
    private let transcriptionQueue = OperationQueue()

    private var cancellables = Set<AnyCancellable>()

    init(appState: AppState, modelManager: WhisperModelManager) {
        self.appState = appState
        self.modelManager = modelManager

        transcriptionQueue.maxConcurrentOperationCount = 1
        transcriptionQueue.qualityOfService = .userInitiated

        observeModelState()
        // 订阅需在 MainActor 上（appState 是 @MainActor 隔离）
        Task { @MainActor [weak self] in self?.observeSelectedModel() }
    }

    // MARK: - Lifecycle

    func start() {
        // 初始加载由 selectedModel 订阅驱动（observeSelectedModel dropFirst 已去掉），
        // 此处保留向后兼容：首次 start() 触发初始模型加载
        Task { [weak self] in
            guard let self else { return }
            let model = await MainActor.run { self.appState.selectedModel }
            NSLog("[TranscriptionService] start() 调用，加载模型: %@", model.rawValue)
            await self.modelManager.ensureModel(model)
        }
    }

    func stop() {
        transcriptionQueue.cancelAllOperations()
    }

    // MARK: - Enqueue Segment

    func enqueue(_ segment: AudioSegment) {
        // switchModel 会先将 whisperContext 置 nil，切换期间此 guard 自然丢弃入队
        guard modelManager.whisperContext != nil else {
            NSLog("[TranscriptionService] 模型切换中，丢弃音频段")
            return
        }

        let op = TranscriptionOperation(
            segment: segment,
            context: modelManager.whisperContext!
        ) { [weak self] result in
            self?.handleResult(result, capturedAt: segment.capturedAt)
        }

        transcriptionQueue.addOperation(op)
    }

    // MARK: - Result Handler

    private func handleResult(_ result: Result<String, Error>, capturedAt: Date) {
        switch result {
        case .success(let text) where !text.isEmpty:
            let entry = TranscriptionEntry(
                text: text,
                timestamp: capturedAt,
                duration: 0
            )
            Task { @MainActor [weak self] in
                self?.appState.appendEntry(entry)
            }
        case .failure(let error):
            print("[TranscriptionService] Error: \(error)")
        default:
            break // empty transcription, skip
        }
    }

    // MARK: - Model State Observation

    private func observeModelState() {
        modelManager.statePublisher
            .sink { [weak self] state in
                switch state {
                case .ready:
                    self?.modelReadyPublisher.send(true)
                case .failed(let error):
                    self?.modelReadyPublisher.send(false)
                    self?.modelErrorPublisher.send(error.localizedDescription)
                    // 下载/加载失败时回退 selectedModel 到上一个成功的 activeModel
                    Task { @MainActor [weak self] in
                        guard let self,
                              let fallback = self.modelManager.activeModel else { return }
                        NSLog("[TranscriptionService] 模型加载失败，回退到 %@", fallback.rawValue)
                        self.appState.selectedModel = fallback
                    }
                default:
                    break
                }
            }
            .store(in: &cancellables)
    }

    /// 订阅 selectedModel 变化，触发热切换（必须在 @MainActor 上调用）
    @MainActor
    private func observeSelectedModel() {
        appState.$selectedModel
            .removeDuplicates()
            .dropFirst() // 跳过初始值，避免与 start() 重复加载
            .sink { [weak self] newModel in
                guard let self else { return }
                NSLog("[TranscriptionService] selectedModel 变化，切换到: %@", newModel.rawValue)
                self.transcriptionQueue.cancelAllOperations()
                Task { [weak self] in
                    await self?.modelManager.switchModel(newModel)
                }
            }
            .store(in: &cancellables)
    }
}

// MARK: - Transcription Operation

private final class TranscriptionOperation: Operation, @unchecked Sendable {
    private let segment: AudioSegment
    private let whisperContext: WhisperContext
    private let completion: (Result<String, Error>) -> Void

    init(segment: AudioSegment, context: WhisperContext, completion: @escaping (Result<String, Error>) -> Void) {
        self.segment = segment
        self.whisperContext = context
        self.completion = completion
    }

    override func main() {
        guard !isCancelled else { return }

        do {
            let text = try whisperContext.transcribe(samples: segment.samples)
            completion(.success(text))
        } catch {
            completion(.failure(error))
        }
    }
}

